public abstract class FromStringDeserializer<T> extends StdDeserializer<T> {

    protected Class<T> _targetType;

    /** Type of "empty" string that means this should default to some kind of default value */
    private int _emptyAsDefault = 0;

    @SuppressWarnings("unchecked")
    protected FromStringDeserializer(Class<?> vc) {
        super((Class<? extends T>)vc);
        _targetType = (Class<T>)vc;
    }

    /* 
    * I added two new methods here from the original version. One handles null values, 
    * another one manages deserialization for the ROOT locale
    */

    /* This method handles serialization for null values */
    protected T _deserializeFromNull() throws IOException {
        return null;
    }

    /* Manages deserialization for the ROOT locale */
    protected T _deserializeFromEmptyString() throws IOException {
       if(_targetType == Locale.class){
           return (T)_defaultValueForNonNormal();
       }
       else{
          return super._deserializeFromEmptyString();
      }
    }

    /* If no normal match was found we simply return the default value */
    protected Object _defaultValueForNonNormal(){
        return Locale.ROOT;
    }

    @Override
    public final T deserialize(JsonParser jp, DeserializationContext ctxt)
            throws IOException, JsonProcessingException {
        JsonToken t = jp.getCurrentToken();
        if (t == JsonToken.VALUE_STRING && _emptyAsDefault != 4) {
            String text = jp.getText().trim();
            if (text.isEmpty()) {
                switch (_emptyAsDefault) {
                    case 1: return _deserializeFromNull();
                    case 2: return _deserializeAbsent();
                    case 3: return _deserializeToNull();
                }
            }
            return _deserialize(text, jp, ctxt);
        } else if (t == JsonToken.NULL && _emptyAsDefault == 1) {
            return _deserializeFromNull();
        }
        throw ctxt.mappingException(handledType(), "Can not deserialize instance of " + handledType().getName()+ " from token "+t);
    }

}

